// Daily standup meeting config
const today = new Date();
const dateStr = today.toISOString().split('T')[0];

return [{ json: {
  topic: `Daily standup ${dateStr}: What did we accomplish? What are we working on today? Any blockers?`,
  agents: ['product-manager', 'engineer-planner', 'engineer-implementer', 'qa-agent'],
  maxRounds: 2,
  autoDiscuss: true,
  meetingType: 'standup',
  telegramChat: 'engineering',
  idempotencyKey: `meeting-standup:${dateStr}`
} }];

// Weekly planning meeting config
const today = new Date();
const weekNum = Math.ceil(((today - new Date(today.getFullYear(), 0, 1)) / 86400000 + new Date(today.getFullYear(), 0, 1).getDay() + 1) / 7);
const dateStr = today.toISOString().split('T')[0];

return [{ json: {
  topic: `Weekly planning (W${weekNum}): Review sprint progress, prioritize upcoming work, identify risks and dependencies. Plan the week ahead.`,
  agents: ['product-manager', 'engineer-planner', 'architect-jets', 'engineer-implementer', 'engineer-reviewer', 'security-agent', 'qa-agent'],
  maxRounds: 3,
  autoDiscuss: true,
  meetingType: 'weekly-planning',
  telegramChat: 'engineering',
  idempotencyKey: `meeting-weekly:${dateStr}`
} }];

